import json

from langchain.agents import create_agent
from pydantic import BaseModel

import models
import prompts
from prompts import forecast_system


class Output(BaseModel):
    """Outputs declared by agent.forecast."""

    summary: str


def run(
    location: str,
) -> Output:
    """Run agent.forecast."""
    variables = {
        "location": location,
    }
    agent = create_agent(
        models.fast(),
        tools=[],
        system_prompt=prompts.render(forecast_system.TEMPLATE, variables),
        response_format=Output,
    )
    result = agent.invoke(
        {"messages": [{"role": "user", "content": json.dumps(variables, sort_keys=True)}]}
    )
    return result["structured_response"]
